#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, X; scanf("%lld %lld", &N, &X);
        long long partner = 2 * N - X + 1;
        printf("%lld\n", partner);
    }
    return 0;
}

